fun solve(landStartTime: Array<Long>, landDuration: Array<Long>, waterStartTime: Array<Long>, waterDuration: Array<Long>): Long {
    var minTime = Long.MAX_VALUE

    for (i in landStartTime.indices) {
        for (j in waterStartTime.indices) {
            // Case 1: land first, then water
            val landStart = landStartTime[i]
            val landEnd = landStart + landDuration[i]
            val waterStart = maxOf(waterStartTime[j], landEnd)
            val waterEnd = waterStart + waterDuration[j]
            val total1 = waterEnd

            // Case 2: water first, then land
            val waterStart2 = waterStartTime[j]
            val waterEnd2 = waterStart2 + waterDuration[j]
            val landStart2 = maxOf(landStartTime[i], waterEnd2)
            val landEnd2 = landStart2 + landDuration[i]
            val total2 = landEnd2

            minTime = minOf(minTime, total1, total2)
        }
    }

    return minTime
}
